import React, { useState } from "react";
import ProductCard from "./components/ProductCard";

const products = [
  { id: 1, name: "Gold Necklace", price: 25000, image: "https://images.unsplash.com/photo-1600180758895-3e2d6c8c2f6d" },
  { id: 2, name: "Diamond Ring", price: 120000, image: "https://images.unsplash.com/photo-1617039624160-3d1c7f8e6a8b" },
  { id: 3, name: "Silver Bracelet", price: 15000, image: "https://images.unsplash.com/photo-1622447032794-4a5c3f8a9f3d" },
  { id: 4, name: "Pearl Earrings", price: 8000, image: "https://images.unsplash.com/photo-1600180758895-3e2d6c8c2f6d" },
  { id: 5, name: "Luxury Watch", price: 200000, image: "https://images.unsplash.com/photo-1523275335684-37898b6baf30" },
  { id: 6, name: "Emerald Pendant", price: 45000, image: "https://images.unsplash.com/photo-1600180758895-3e2d6c8c2f6d" }
];

function App() {
  const [cart, setCart] = useState([]);
  const [page, setPage] = useState("home");

  const addToCart = (product) => {
    setCart([...cart, product]);
  };

  const removeFromCart = (index) => {
    const newCart = [...cart];
    newCart.splice(index, 1);
    setCart(newCart);
  };

  const totalPrice = cart.reduce((sum, item) => sum + item.price, 0);

  return (
    <div className="bg-gray-100 min-h-screen">
      <header className="shadow p-4 flex justify-between items-center">
        <h1 className="text-xl font-bold">Luxe Jewellery</h1>
        <nav>
          <button onClick={() => setPage("home")} className="px-3">Home</button>
          <button onClick={() => setPage("products")} className="px-3">Products</button>
          <button onClick={() => setPage("contact")} className="px-3">Contact</button>
          <button onClick={() => setPage("cart")} className="px-3">Cart ({cart.length})</button>
        </nav>
      </header>

      {page === "home" && (
        <section className="p-6 text-center">
          <img 
            src="https://images.unsplash.com/photo-1600180758895-3e2d6c8c2f6d" 
            alt="Luxury Jewellery Showcase" 
            className="w-full h-96 object-cover rounded mb-6"
          />
          <h2 className="text-3xl font-bold text-gold">Welcome to Luxe Jewellery</h2>
          <p className="text-gray-700 mt-2">Discover timeless elegance and luxury crafted for you.</p>
        </section>
      )}

      {page === "products" && (
        <main className="p-6 grid grid-cols-1 md:grid-cols-3 gap-6">
          {products.map(p => (
            <ProductCard key={p.id} {...p} addToCart={() => addToCart(p)} />
          ))}
        </main>
      )}

      {page === "cart" && (
        <section className="p-6">
          <h2 className="text-2xl font-bold mb-4">Your Cart</h2>
          {cart.length === 0 ? (
            <p className="text-gray-600">Your cart is empty.</p>
          ) : (
            <>
              <ul>
                {cart.map((item, index) => (
                  <li key={index} className="bg-white shadow rounded p-4 mb-2 flex justify-between items-center">
                    <span>{item.name} - KSh {item.price.toLocaleString()}</span>
                    <button 
                      onClick={() => removeFromCart(index)} 
                      className="bg-red-600 text-white px-3 py-1 rounded hover:bg-red-800"
                    >
                      Remove
                    </button>
                  </li>
                ))}
              </ul>
              <div className="mt-4 font-bold">Total: KSh {totalPrice.toLocaleString()}</div>
              <button 
                onClick={() => setPage("checkout")} 
                className="mt-4 bg-green-600 text-white px-4 py-2 rounded hover:bg-green-800"
              >
                Proceed to Checkout
              </button>
            </>
          )}
        </section>
      )}

      {page === "checkout" && (
        <section className="p-6">
          <h2 className="text-2xl font-bold mb-4">Checkout</h2>
          <p className="text-gray-600 mb-4">Total Amount: KSh {totalPrice.toLocaleString()}</p>
          <form className="bg-white shadow rounded p-4 max-w-md mx-auto">
            <label className="block mb-2">Name on Card</label>
            <input type="text" className="border p-2 w-full mb-4" placeholder="John Doe" />

            <label className="block mb-2">Card Number</label>
            <input type="text" className="border p-2 w-full mb-4" placeholder="1234 5678 9012 3456" />

            <label className="block mb-2">Expiry Date</label>
            <input type="text" className="border p-2 w-full mb-4" placeholder="MM/YY" />

            <label className="block mb-2">CVV</label>
            <input type="text" className="border p-2 w-full mb-4" placeholder="123" />

            <button type="submit" className="bg-black text-yellow-400 px-4 py-2 rounded hover:bg-gray-800">
              Pay Now
            </button>
          </form>
        </section>
      )}

      {page === "contact" && (
        <footer className="bg-black p-4 text-center">
          <p className="text-white">Contact us at info@luxejewels.com</p>
        </footer>
      )}
    </div>
  );
}

export default App;
